-- SupplyFlow — neutral demo tenant package.
--
-- This is NOT what a real new tenant gets. It exists to *show the product working* —
-- sales demos, and developing against realistic data. The neutral baseline a real
-- install gets is supabase/seed.sql.
--
-- Everything here belongs to ONE organization (the reserved demo org id below) and is
-- designed to be loaded ALONGSIDE real tenants: RLS isolates it like any other tenant.
--
-- Contents: 15 suppliers, 46 products, overlapping supplier prices + history, orders in
-- every status, partial receipts, and the deliberately seeded financial edge cases the
-- demo script depends on:
--   * duplicate invoice 7702 (בשר והבן, 03.07) — the duplicate engine's showpiece
--   * one partial payment · one payment covering several invoices · one invoice paid
--     by several payments · open credits · credit offset against a payment
--   * matched / suggested / unmatched bank transactions · exceptions per role
-- Do not "tidy" these away — they are the demo's entire value.
--
-- ===== Loading =====
--   1. scripts\create-users.ps1     — creates the demo auth users (once per project)
--   2. scripts\seed-demo.ps1        — reset + this file, in one command
-- By hand, applying each file as a SINGLE script/session (the pg_temp helper below is
-- session-scoped):
--   .\scripts\db-query.ps1 -SqlFile supabase\demo\demo_reset.sql
--   .\scripts\db-query.ps1 -SqlFile supabase\demo\demo_seed.sql
--
-- ===== Storage =====
-- No `documents` rows are seeded (there are no demo files to point them at). If demo
-- files are ever added, the object path MUST be {org_id}/{entity_type}/{entity_id}/{file}:
-- the bucket policy (migration 0005) matches the leading folder against auth_org(), so
-- any other layout returns 403. For example:
--   11111111-1111-4111-8111-111111111111/invoice/f4000000-0000-4000-8000-000000000009/scan.jpg

-- ===== Guards: never load twice, never load half-formed =====
do $$
begin
  if exists (select 1 from organizations where id = '11111111-1111-4111-8111-111111111111') then
    raise exception 'Demo org is already loaded. Run supabase/demo/demo_reset.sql first (or use scripts/seed-demo.ps1).';
  end if;

  if (select count(*) from auth.users where email in
      ('owner@demo.supplyflow.local','kitchen@demo.supplyflow.local','office@demo.supplyflow.local','payer@demo.supplyflow.local','accountant@demo.supplyflow.local')) < 5 then
    raise exception 'Demo auth users are missing. Run scripts/create-users.ps1 first.';
  end if;
end $$;

-- ===== Organization & profiles =====
-- Reserved demo org id. Real tenants are provisioned with gen_random_uuid(), so this
-- literal is never handed to a paying customer and cannot collide with one.
--
-- status is set explicitly rather than left to the 'trial' default from migration 0006:
-- the demo has to behave like a live customer, and 0006 itself backfills every
-- pre-existing organization to 'active' (0006_platform_admin.sql:40) — this org is one of
-- them. Only 'suspended' would actually lock it out (auth_org() returns null), but a demo
-- tenant sitting in 'trial' would misrepresent the product on a sales call.
-- Requires migration 0006 to be applied first.
insert into organizations (id, name, vat_rate, status) values
('11111111-1111-4111-8111-111111111111', 'עסק לדוגמה', 18.00, 'active');

-- profiles.id IS the auth.users id, so it cannot be hardcoded — create-users.ps1 lets
-- Supabase mint it. Resolve by email instead. (The previous hardcoded UUIDs could only
-- ever apply to the one project they were copied from.)
insert into profiles (id, org_id, full_name, role, phone)
select u.id, '11111111-1111-4111-8111-111111111111', x.full_name, x.role::user_role, x.phone
from (values
  ('owner@demo.supplyflow.local',      'בעלים לדוגמה',       'owner',      '050-5551111'),
  ('kitchen@demo.supplyflow.local',    'צוות תפעול לדוגמה',  'kitchen',    '052-5552222'),
  ('office@demo.supplyflow.local',     'משרד לדוגמה',        'office',     '053-5553333'),
  ('payer@demo.supplyflow.local',      'מבצע תשלום לדוגמה',  'payer',      '054-5554444'),
  ('accountant@demo.supplyflow.local', 'רו״ח לדוגמה',        'accountant', '050-5555555')
) as x(email, full_name, role, phone)
join auth.users u on u.email = x.email;

-- Every later reference to a demo user resolves through this, for the same reason.
create function pg_temp.demo_user(p_role text) returns uuid
language sql stable as $fn$
  select id from profiles
  where org_id = '11111111-1111-4111-8111-111111111111' and role = p_role::user_role
  limit 1
$fn$;

